func ReadBitset256(ctx *runtime.ReadContext, addr uintptr) (*Bitset256, runtime.Errors) {
	var errs runtime.Errors
	result := &Bitset256{}
	var buf [32]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("Bitset256", uintptr(addr), err)
		return result, errs
	}

	for i := range result.Words {
		result.Words[i] = binary.LittleEndian.Uint32(buf[0+i*4:])
	}
	return result, errs
}

func ReadConfigDamagesByType(ctx *runtime.ReadContext, addr uintptr) (*ConfigDamagesByType, runtime.Errors) {
	var errs runtime.Errors
	result := &ConfigDamagesByType{}
	var buf [64]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("ConfigDamagesByType", uintptr(addr), err)
		return result, errs
	}

	result.Vtable = binary.LittleEndian.Uint32(buf[0:])
	result.Melee = math.Float32frombits(binary.LittleEndian.Uint32(buf[4:]))
	result.Projectile = math.Float32frombits(binary.LittleEndian.Uint32(buf[8:]))
	result.Explosion = math.Float32frombits(binary.LittleEndian.Uint32(buf[12:]))
	result.Electricity = math.Float32frombits(binary.LittleEndian.Uint32(buf[16:]))
	result.Fire = math.Float32frombits(binary.LittleEndian.Uint32(buf[20:]))
	result.Drill = math.Float32frombits(binary.LittleEndian.Uint32(buf[24:]))
	result.Slice = math.Float32frombits(binary.LittleEndian.Uint32(buf[28:]))
	result.Ice = math.Float32frombits(binary.LittleEndian.Uint32(buf[32:]))
	result.Healing = math.Float32frombits(binary.LittleEndian.Uint32(buf[36:]))
	result.PhysicsHit = math.Float32frombits(binary.LittleEndian.Uint32(buf[40:]))
	result.Radioactive = math.Float32frombits(binary.LittleEndian.Uint32(buf[44:]))
	result.Poison = math.Float32frombits(binary.LittleEndian.Uint32(buf[48:]))
	result.Overeating = math.Float32frombits(binary.LittleEndian.Uint32(buf[52:]))
	result.Curse = math.Float32frombits(binary.LittleEndian.Uint32(buf[56:]))
	result.Holy = math.Float32frombits(binary.LittleEndian.Uint32(buf[60:]))
	return result, errs
}

func ReadComponentHeader(ctx *runtime.ReadContext, addr uintptr) (*ComponentHeader, runtime.Errors) {
	var errs runtime.Errors
	result := &ComponentHeader{}
	var buf [72]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("ComponentHeader", uintptr(addr), err)
		return result, errs
	}

	result.Vtable = binary.LittleEndian.Uint32(buf[0:])
	result.BufferIndex = int32(binary.LittleEndian.Uint32(buf[4:]))
	result.PTypeName = binary.LittleEndian.Uint32(buf[8:])
	result.TypeId = int32(binary.LittleEndian.Uint32(buf[12:]))
	result.Unknown10 = binary.LittleEndian.Uint32(buf[16:])
	result.Active = buf[20] != 0
	copy(result.ComponentTags[:], buf[24:56])
	result.Unknown38 = binary.LittleEndian.Uint32(buf[56:])
	result.Unknown3c = binary.LittleEndian.Uint32(buf[60:])
	result.Unknown40 = binary.LittleEndian.Uint32(buf[64:])
	result.Unknown44 = binary.LittleEndian.Uint32(buf[68:])
	return result, errs
}

func ReadMsvcString(ctx *runtime.ReadContext, addr uintptr) (*MsvcString, runtime.Errors) {
	var errs runtime.Errors
	result := &MsvcString{}
	var buf [24]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("MsvcString", uintptr(addr), err)
		return result, errs
	}

	copy(result.Data[:], buf[0:16])
	result.Length = binary.LittleEndian.Uint32(buf[16:])
	result.Capacity = binary.LittleEndian.Uint32(buf[20:])
	return result, errs
}

func ReadVec2(ctx *runtime.ReadContext, addr uintptr) (*Vec2, runtime.Errors) {
	var errs runtime.Errors
	result := &Vec2{}
	var buf [8]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("Vec2", uintptr(addr), err)
		return result, errs
	}

	result.X = math.Float32frombits(binary.LittleEndian.Uint32(buf[0:]))
	result.Y = math.Float32frombits(binary.LittleEndian.Uint32(buf[4:]))
	return result, errs
}

func ReadIKLimbAttackerComponent(ctx *runtime.ReadContext, addr uintptr) (*IKLimbAttackerComponent, runtime.Errors) {
	var errs runtime.Errors
	result := &IKLimbAttackerComponent{}
	var buf [132]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("IKLimbAttackerComponent", uintptr(addr), err)
		return result, errs
	}

	// Field: Header at int64(addr)+0
	{
		child, childErrs := ReadComponentHeader(ctx, uintptr(int64(addr)+0))
		if child != nil {
			result.Header = *child
		}
		errs = append(errs, childErrs...)
	}

	result.Radius = math.Float32frombits(binary.LittleEndian.Uint32(buf[72:]))
	result.LegVelocityCoeff = math.Float32frombits(binary.LittleEndian.Uint32(buf[76:]))
	result.TargetingRadius = math.Float32frombits(binary.LittleEndian.Uint32(buf[80:]))
	result.TargetingRaytrace = buf[84] != 0
	// Field: TargetEntitiesWithTag at int64(addr)+88
	{
		child, childErrs := ReadMsvcString(ctx, uintptr(int64(addr)+88))
		if child != nil {
			result.TargetEntitiesWithTag = *child
		}
		errs = append(errs, childErrs...)
	}

	// Field: MTarget at int64(addr)+112
	{
		child, childErrs := ReadVec2(ctx, uintptr(int64(addr)+112))
		if child != nil {
			result.MTarget = *child
		}
		errs = append(errs, childErrs...)
	}

	result.MTargetEntity = int32(binary.LittleEndian.Uint32(buf[120:]))
	result.Unknown7c = binary.LittleEndian.Uint32(buf[124:])
	result.MStateTimer = math.Float32frombits(binary.LittleEndian.Uint32(buf[128:]))
	return result, errs
}

