func ReadGlobalStats(ctx *runtime.ReadContext, addr uintptr) (*GlobalStats, runtime.Errors) {
	var errs runtime.Errors
	result := &GlobalStats{}
	var buf [832]byte

	if _, err := ctx.ReadAt(buf[:], int64(addr)); err != nil {
		errs.Add("GlobalStats", uintptr(addr), err)
		return result, errs
	}

	result.Vtable = binary.LittleEndian.Uint32(buf[0:])
	result.STATSVERSION = int32(binary.LittleEndian.Uint32(buf[4:]))
	result.DEBUGHOWMANYTIMESDONE = int32(binary.LittleEndian.Uint32(buf[8:]))
	result.DEBUGISON = buf[12] != 0
	result.DEBUGHOWMANYRESETS = int32(binary.LittleEndian.Uint32(buf[16:]))
	result.DEBUGFIXEDSTATS = buf[20] != 0
	result.SessionDead = buf[21] != 0
	result.KEYVALUESTATS = binary.LittleEndian.Uint64(buf[24:])
	copy(result.Session[:], buf[32:232])
	copy(result.Highest[:], buf[232:432])
	copy(result.Global[:], buf[432:632])
	copy(result.PrevBest[:], buf[632:832])
	return result, errs
}

